mapper.select:
SELECT wo.*, u1.real_name as reporterName, u2.real_name as engineerName FROM work_order wo LEFT JOIN sys_user u1 ON wo.reporter_id = u1.id LEFT JOIN sys_user u2 ON wo.engineer_id = u2.id
AND wo.status = #{query.status}
AND wo.reporter_id = #{query.reporterId}
AND wo.engineer_id = #{query.engineerId}
AND (wo.title LIKE CONCAT('%', #{query.keyword}, '%') OR wo.order_no LIKE CONCAT('%', #{query.keyword}, '%'))
ORDER BY wo.create_time DESC
